import { createTheme } from "@mui/material/styles";
import AvenirHeavy from './fonts/AvenirLTStd-Heavy.otf';
import AvenirBlack from './fonts/AvenirLTStd-Black.otf';
import AvenirRoman from './fonts/AvenirLTStd-Roman.otf';
import AvenirLight from './fonts/AvenirLTStd-Light.otf';


const appTheme = createTheme({
    typography: {
        h1: {
          fontFamily: 'Avenir',
          fontSize: '24px',
          fontWeight: 400,
        }
      },
      palette: {
        primary: {
            main: '#D4415B',
            dark: '#79053D',
            light: '#E07A8D',
            background: '#DEBAC1',
            contrastText: '#FFFFFF'
        },
        secondary: {
            main: '#C13DAC',
            dark: '#862576',
            light: '#EA8DDB',
            background: '#E8B9E0'
        }
      },
      components: {
        MuiCssBaseline: {
          styleOverrides: `
            @font-face {
              font-family: 'Avenir';
              font-style: normal;
              font-display: swap;
              font-weight: 900;
              src: url(${AvenirBlack});
            },
            @font-face {
              font-family: 'Avenir';
              font-style: normal;
              font-display: swap;
              font-weight: 700;
              src: url(${AvenirHeavy});
            },
          `,
        },
      }
});

export default appTheme;
